class Solution:
    def predictTheWinner(self, nums):
        from functools import lru_cache
        n = len(nums)
        @lru_cache(maxsize=None)
        def best(i, j):
            if i > j:
                return 0
            take_left = nums[i] - best(i + 1, j)
            take_right = nums[j] - best(i, j - 1)
            return max(take_left, take_right)
        return best(0, n - 1) >= 0

